#include <iostream>
using namespace std;

class Transaction {
    int& value;
    int original;
public:
    Transaction(int& v) : value(v), original(v) {}
    void commit() { original = value; }
    ~Transaction() { value = original; }
};

void modify(int& x) {
    Transaction t(x);
    x = 100;
    throw 1; // Rollback
}

int main() {
    int val = 10;
    try { modify(val); } catch (int) {}
    cout << val;
    return 0;
}

